INSERT INTO `litemall_comment` VALUES (1012,1181004,0,'质量很好，面料舒适，穿着很舒服，推荐购买！','感谢您的支持与认可！',1,0,NULL,5,'2026-02-20 09:44:36','2026-02-27 09:44:36',0),(1013,1181004,0,'颜色和图片一样，没有色差，尺码标准。','',2,0,NULL,4,'2026-02-21 09:44:36','2026-02-27 09:44:36',0),(1014,1181005,0,'牛仔裤版型很好，显瘦，做工精细。','感谢您的认可！',3,0,NULL,5,'2026-02-22 09:44:36','2026-02-27 09:44:36',0),(1015,1181005,0,'面料有点硬，洗过之后好一些了。','牛仔面料新衣会稍硬，感谢反馈！',4,0,NULL,3,'2026-02-23 09:44:36','2026-02-27 09:44:36',0),(1016,1181006,0,'羽绒服很轻便，保暖效果不错，冬天穿正合适。','感谢您的支持！',5,0,NULL,5,'2026-02-24 09:44:36','2026-02-27 09:44:36',0),(1017,1181006,0,'颜色比图片深一点，不过也很好看。','',6,0,NULL,4,'2026-02-25 09:44:36','2026-02-27 09:44:36',0),(1018,1181007,0,'衬衫面料很舒服，透气性好，夏天穿很凉快。','感谢您的评价！',7,0,NULL,5,'2026-02-25 09:44:36','2026-02-27 09:44:36',0),(1019,1181007,0,'尺码偏小，建议买大一号。','感谢您的反馈！',8,0,NULL,3,'2026-02-26 09:44:36','2026-02-27 09:44:36',0),(1020,1181008,0,'风衣版型很好看，穿上很有气质，质量也很好。','',9,0,NULL,5,'2026-02-26 09:44:36','2026-02-27 09:44:36',0),(1021,1181008,0,'卡其色很百搭，适合各种场合穿。','感谢您的认可！',10,0,NULL,5,'2026-02-27 09:44:36','2026-02-27 09:44:36',0);
