INSERT INTO `litemall_issue` VALUES (5,'如何选择合适的尺码？','建议您参考商品详情页的尺码表，根据您的身高体重选择合适的尺码。','2026-02-27 09:44:36','2026-02-27 09:44:36',0),(6,'支持哪些支付方式？','我们支持微信支付、支付宝、银联卡等多种支付方式。','2026-02-27 09:44:36','2026-02-27 09:44:36',0),(7,'发货后多久能收到？','一般订单发货后1-3个工作日可送达。','2026-02-27 09:44:36','2026-02-27 09:44:36',0),(8,'如何申请退换货？','在\"我的订单\"中找到需要售后的订单，点击\"申请售后\"即可。','2026-02-27 09:44:36','2026-02-27 09:44:36',0),(9,'会员有什么优惠？','会员可享受专属折扣、积分抵现、优先发货等特权。','2026-02-27 09:44:36','2026-02-27 09:44:36',0);
