INSERT INTO `litemall_topic` VALUES (401,'川着transmute 春日穿搭指南','2026春夏流行趋势','<p>川着transmute为你带来2026春夏最新流行趋势。从优雅连衣裙到干练西装，让你轻松驾驭各种场合。</p><p><img src=\"/images/goods/dress.png\" style=\"width:100%\"/></p>',0.00,'3256','http://47.107.151.70:8088/wx/storage/fetch/gxtx0lo47zlmn6ziybmf.png',1,'','2026-03-13 09:32:01','2026-03-13 09:32:01',0),(402,'职场女性穿搭攻略','穿出专业范儿，展现自信魅力','<p>职场穿搭不仅仅是着装，更是展现专业态度和个人魅力的重要方式。川着transmute精选西装、衬衫、裤装，助你打造完美职场形象。</p><p><img src=\"/images/goods/suit.png\" style=\"width:100%\"/></p>',0.00,'2086','http://47.107.151.70:8088/wx/storage/fetch/ywxkhub46fzvakpvv9fo.png',2,'','2026-03-13 09:32:01','2026-03-13 09:32:01',0),(403,'约会穿搭灵感','浪漫约会。从穿搭开始','<p>约会穿什么？川着transmute为你精选浪漫连衣裙、温柔针织衫，让你在约会中展现最美的一面。</p><p><img src=\"/images/goods/knit.png\" style=\"width:100%\"/></p>',0.00,'2580','http://47.107.151.70:8088/wx/storage/fetch/f4kiq2k1uyrjxxspjuxr.png',3,'','2026-03-13 09:32:01','2026-03-13 09:32:01',0),(404,'基础款穿搭技巧','基础款也能穿出高级感','<p>白T恤、牛仔裤、小黑裙...这些基础款如何穿出高级感？川着transmute教你搭配技巧，让简约成为你的风格标签。</p><p><img src=\"/images/goods/shirt.png\" style=\"width:100%\"/></p>',0.00,'3345','http://47.107.151.70:8088/wx/storage/fetch/qkru9uls535344yxf192.png',4,'','2026-03-13 09:32:01','2026-03-13 09:32:01',0);
/*!40000 ALTER TABLE `litemall_topic` ENABLE KEYS */;
